**HttpTransport implementation:**

```typescript
async scan(
  options: TransportScanOptions,
  onEvent: (event: TransportScanEvent) => void,
  signal?: AbortSignal,
): Promise<void> {
  const response = await fetch(`${this.baseUrl}/api/discovery/scan`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(options),
    signal,
  });

  if (!response.ok) {
    const body = await response.json().catch(() => ({ error: response.statusText }));
    throw new Error(body.error ?? `HTTP ${response.status}`);
  }

  const reader = response.body!.getReader();
  const decoder = new TextDecoder();
  let buffer = '';

  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop() || '';

      let eventType = '';
      for (const line of lines) {
        if (line.startsWith('event: ')) {
          eventType = line.slice(7).trim();
        } else if (line.startsWith('data: ') && eventType) {
          try {
            const data = JSON.parse(line.slice(6));
            onEvent({ type: eventType, data } as TransportScanEvent);
          } catch {
            // Skip malformed JSON lines
          }
          eventType = '';
        }
      }
    }
  } finally {
    reader.releaseLock();
  }
}
```

**DirectTransport implementation:**

The DirectTransport is used in the Obsidian plugin where scanner runs in-process. Import `unifiedScan` from `@dorkos/mesh` and call it directly:

```typescript
async scan(
  options: TransportScanOptions,
  onEvent: (event: TransportScanEvent) => void,
  signal?: AbortSignal,
): Promise<void> {
  for (const root of options.roots) {
    for await (const event of this.meshCore.discover([root], {
      maxDepth: options.maxDepth,
      timeout: options.timeout,
    })) {
      if (signal?.aborted) return;
      if (event.type !== 'auto-import') {
        onEvent(event as TransportScanEvent);
      }
    }
  }
}
```

