**discovery-store.ts:**

```typescript
import { create } from 'zustand';
import type { DiscoveryCandidate } from '@dorkos/shared/mesh-schemas';

interface ScanProgress {
  scannedDirs: number;
  foundAgents: number;
}

interface DiscoveryState {
  candidates: DiscoveryCandidate[];
  progress: ScanProgress | null;
  isScanning: boolean;
  error: string | null;
  lastScanAt: number | null;
}

interface DiscoveryActions {
  addCandidate: (candidate: DiscoveryCandidate) => void;
  setProgress: (progress: ScanProgress) => void;
  startScan: () => void;
  completeScan: (progress: ScanProgress) => void;
  setError: (error: string) => void;
  clear: () => void;
}

export const useDiscoveryStore = create<DiscoveryState & DiscoveryActions>((set) => ({
  candidates: [],
  progress: null,
  isScanning: false,
  error: null,
  lastScanAt: null,

  addCandidate: (candidate) =>
    set((state) => ({ candidates: [...state.candidates, candidate] })),
  setProgress: (progress) => set({ progress }),
  startScan: () => set({ candidates: [], progress: null, error: null, isScanning: true }),
  completeScan: (progress) =>
    set({ progress, isScanning: false, lastScanAt: Date.now() }),
  setError: (error) => set({ error, isScanning: false }),
  clear: () => set({ candidates: [], progress: null, error: null, lastScanAt: null }),
}));
```

**use-discovery-scan.ts:**

```typescript
import { useCallback, useRef } from 'react';
import { useTransport } from '@/layers/shared/model';
import { useDiscoveryStore } from './discovery-store';

export function useDiscoveryScan() {
  const transport = useTransport();
  const store = useDiscoveryStore();
  const abortRef = useRef<AbortController | null>(null);

  const scan = useCallback(
    (roots?: string[], maxDepth?: number) => {
      abortRef.current?.abort();
      const controller = new AbortController();
      abortRef.current = controller;

      store.startScan();

      void transport
        .scan(
          { roots: roots ?? [], maxDepth },
          (event) => {
            switch (event.type) {
              case 'candidate':
                store.addCandidate(event.data as DiscoveryCandidate);
                break;
              case 'progress':
                store.setProgress(event.data as ScanProgress);
                break;
              case 'complete':
                store.completeScan(event.data as ScanProgress);
                break;
              case 'error':
                store.setError((event.data as { error: string }).error);
                break;
            }
          },
          controller.signal,
        )
        .catch((err: Error) => {
          if (err.name !== 'AbortError') {
            store.setError(err.message);
          }
        });
    },
    [transport, store],
  );

  const cancel = useCallback(() => {
    abortRef.current?.abort();
  }, []);

  return {
    candidates: store.candidates,
    isScanning: store.isScanning,
    progress: store.progress,
    error: store.error,
    lastScanAt: store.lastScanAt,
    scan,
    cancel,
  };
}
```

Note: When `roots` is empty array, the server defaults to the boundary (home directory).

