import { describe, it, expect, beforeEach } from 'vitest';
import { useDiscoveryStore } from '../model/discovery-store';

describe('useDiscoveryStore', () => {
  beforeEach(() => {
    useDiscoveryStore.getState().clear();
  });

  it('startScan clears previous results and sets isScanning', () => {
    useDiscoveryStore.getState().addCandidate({ path: '/old', strategy: 'claude-code', hints: {}, discoveredAt: '' });
    useDiscoveryStore.getState().startScan();
    const state = useDiscoveryStore.getState();
    expect(state.candidates).toEqual([]);
    expect(state.isScanning).toBe(true);
    expect(state.error).toBeNull();
  });

  it('addCandidate appends to candidates array', () => {
    const candidate = { path: '/test', strategy: 'claude-code', hints: {}, discoveredAt: '' };
    useDiscoveryStore.getState().addCandidate(candidate);
    expect(useDiscoveryStore.getState().candidates).toHaveLength(1);
  });

  it('completeScan sets lastScanAt and clears isScanning', () => {
    useDiscoveryStore.getState().startScan();
    useDiscoveryStore.getState().completeScan({ scannedDirs: 100, foundAgents: 3 });
    const state = useDiscoveryStore.getState();
    expect(state.isScanning).toBe(false);
    expect(state.lastScanAt).toBeGreaterThan(0);
  });

  it('clear resets all state', () => {
    useDiscoveryStore.getState().addCandidate({ path: '/test', strategy: 'claude-code', hints: {}, discoveredAt: '' });
    useDiscoveryStore.getState().clear();
    const state = useDiscoveryStore.getState();
    expect(state.candidates).toEqual([]);
    expect(state.lastScanAt).toBeNull();
  });
});
```

